final:
module JK_Latch (
    input obf_J,
    input K,
    input clk,
    output reg Q
);
    always @(posedge clk) begin
        if (obf_J == 1 && K == 0)
            Q <= 1;         // Set
        else if (obf_J == 0 && K == 1)
            Q <= 0;         // Reset
        else if (obf_J == 1 && K == 1)
            Q <= ~Q;        // Toggle
        // else retain previous state
    end
endmodule
